  ('optometrist-moex-00714', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '矽氧烷丙烯酸（siloxaneacrylates,SAs）與氟矽氧烷丙烯酸（fluoro-siloxaneacrylates,FSAs）的比較敘 述，下列何者錯誤？', '["矽氧烷丙烯酸有較差的傳氧性", "氟矽氧烷丙烯酸有較高的抗沉澱作用", "氟矽氧烷丙烯酸有較佳的抗變形與抗刮傷", "氟矽氧烷丙烯酸有較低的表面電荷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00715', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列何者為美國食品藥物管理局（FDA）核准可用於作為7天延長配戴型隱形眼鏡之材質？', '["BostonEO（fluorosiliconeacrylate）", "BostonEqualens（fluorosiliconeacrylate）", "Optacryl60（siliconeacrylate）", "HybridFS（fluorosiliconeacrylate）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00716', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有一軟式隱形眼鏡材質含水量38%，如果想提高其含水量，下列何種材質單體最不合適？', '["乙二醇二甲基丙烯酸酯（ethyleneglycoldimethacrylate）", "甲基丙烯酸（methacrylicacid）", "N-乙烯基吡咯烷酮（N-vinylpyrrolidone）", "聚乙烯醇（polyvinylalcohol）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00717', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '硬式材質fluoro-silicone/acrylate（F-S/A）與silicone/acrylate（S/A）相比較，下列敘述何者錯誤？', '["F-S/A鏡片淚液破裂點較慢", "S/A鏡片沉澱物較多", "F-S/A鏡片表面張力較低", "S/A鏡片尺寸較穩定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00718', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '水膠鏡片的表面特性將直接影響其與淚膜的相互作用，並因此影響其在眼睛環境中的生物相容性，下 列何者正確？', '["眼瞼和鏡片表面之間的摩擦會導致隱形眼鏡相關的乳頭狀結膜炎（contact lens related papillary conjunctivitis）和眼瞼摩擦的上皮病變（lidwiperepitheliopathy）", "如果不能在眼睛中維持穩定的淚液層，會降低視覺品質，且不易有沉積物在鏡片上", "矽水凝膠材質鏡片潤濕性極佳，幫助維持穩定的淚液層", "穩定的淚液層與鏡片配戴舒適性無關"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00719', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '好的防腐劑（preservative）應具備之功能，不包括下列何者？', '["提供必要程度的殺菌或抑菌功能", "避免產生毒性反應", "增加鏡片表面潤濕性", "增強與淚膜的相容性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00720', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關軟式隱形眼鏡保養的敘述，下列何者錯誤？', '["戴著隱形眼鏡淋浴容易增加感染阿米巴角膜炎的機會", "根據統計，使用消毒液搓揉隱形眼鏡最多可以去除50%在隱形眼鏡的阿米巴病原菌", "戴隱形眼鏡游泳容易增加感染阿米巴角膜炎的機會", "雖然新型的保養液殺菌力強，但是搭配指腹搓洗隱形眼鏡可以達到更好的殺菌效果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00721', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關軟式隱形眼鏡的熱消毒（thermaldisinfection），下列敘述何者錯誤？', '["可能會縮短隱形眼鏡壽命", "使用此消毒方法所造成巨大乳突性結膜炎的機會減少", "廠商現在已經不提供此消毒系統給個人使用（individualuse），而僅提供用於醫療院所內隱形眼鏡的 消毒（in-officedisinfection）", "當短期使用時，熱消毒為最便宜且最有效率的消毒系統"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00722', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '若以球面硬式隱形眼鏡試裝配於一隻眼上，所得螢光染色圖形如下圖，則下列推測何者正確？', '["此角膜有逆向散光", "鏡片基弧對角膜弧度而言相對陡峭", "將鏡片基弧變平可得下圖", "一樣設計的試片，選擇不同基弧，用於此角膜上之最佳螢光圖形為下圖"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00723', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關散光硬式隱形眼鏡，下列敘述何者錯誤？', '["對齊雙散鏡片（alignmentbitoriclens）之前後散光軸是呈90度夾角的", "後表面散光鏡片適用於當殘餘散光與誘發散光可互相抵銷時", "前散光鏡片要發揮功能，要避免鏡片發生旋轉", "斜向雙散鏡片（obliquebitoriclens）製作困難，很少使用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
